11	type Item = { type: string };
12	type Step = { op: "quote"; items: Item[] };
13	type Scenario = { customer: unknown; steps: Step[] };
14	
15	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
16	
17	const sumItemPremiums = (items: Item[]): number => {
18	  const runes = items.filter((i) => i.type === "rune").length;
19	  if (runes === 3) return 60;
20	  return items.reduce((sum, item) => sum + itemBasePremium(item), 0);
21	};
22	
23	const quote = (step: Step): { premium: number } => ({
24	  premium: sumItemPremiums(step.items) + PROCESSING_FEE,
25	});
26	
27	export const runScenario = (input: unknown): unknown => {
28	  const scenario = input as Scenario;
29	  return { results: scenario.steps.map(quote) };
30	};
